Accordion.jinjaAccordionContent.jinjaAccordionItem.jinjaAccordionTrigger.jinja <pre><code>{# def
className: str = ""
#}

&lt;div
  x-data="{
      activeItem: undefined,
      toggleItem(value) {
        this.activeItem = this.activeItem === value ? undefined : value;
      }
    }"
  x-init="console.log('initial state:', activeItem);"
  class="{{ className }} w-full"
  {{ attrs.render() }}
&gt;
  {{ content }}
&lt;/div&gt;
</code></pre> <pre><code>{# def
className: str = ""
#}

&lt;div
  x-show="isOpen"
  x-transition:enter="transition ease-out duration-300"
  x-transition:enter-start="opacity-0 max-h-0"
  x-transition:enter-end="opacity-100 max-h-xl"
  x-transition:leave="transition ease-in duration-300"
  x-transition:leave-start="opacity-100 max-h-xl"
  x-transition:leave-end="opacity-0 max-h-0"
  class="{{ className }} overflow-hidden text-sm"
  {{ attrs.render() }}
&gt;
  &lt;div class="pb-4 pt-0"&gt;{{ content }}&lt;/div&gt;
&lt;/div&gt;
</code></pre> <pre><code>{# def
value: str = "",
className: str = ""
#}

&lt;div
