&lt;/div&gt;
</code></pre> <pre><code>{# def
className: str = ""
#}

&lt;h3 class="flex"&gt;
  &lt;button
    type="button"
    class="{{ className }} flex flex-1 items-center justify-between py-4 font-medium transition-all hover:underline"
    @click="toggleItem($el.closest('[value]').getAttribute('value'))"
